// ============================================
// WF-08 v1: PIPELINE PULSE SEMANAL (Coaching Digest)
// Bambu Tech Services - Automatizacion Comercial con IA
// ============================================
// Genera coaching cards semanales por rep + resumen ejecutivo para CGO
// usando data de Pipedrive (deals) y Google Sheet WF-03 Alert Log.
//
// Flujo n8n esperado:
//   Schedule Trigger (Cron Vie 5pm)
//     -> HTTP Request "Get Pipedrive Deals"        (paginado)
//     -> Code "Consolidate Deals"                  (devuelve 1 item con {deals})
//     -> Google Sheets "Read WF-03 Alerts"         (Get Rows, tab: Alertas)
//     -> Code "Build Coaching Digest"              (ESTE CODIGO, modo: Run Once for All Items)
//     -> Send Email                                (loop: 1 por rep + 1 CGO)
//     -> Google Sheets "Append WF-08 Log"          (tab: CoachingLog)
//
// Modo: Run Once for All Items
// ============================================


// ============================================
// SECCION 1: CONFIGURACION
// ============================================
// IMPORTANTE: mantener sincronizado con WF-03-Code-Node.js
// Si cambias SALES_TEAM o STAGE_CONFIG en WF-03, copialo aqui.

const STAGE_CONFIG = {
  7:  { name: 'Re-contactar / Re-intentar', maxDays: 30, roles: ['pre_sales'] },
  8:  { name: 'MQL - Lead Frio',            maxDays: 5,  roles: ['pre_sales'] },
  1:  { name: 'Lead In - BANT',             maxDays: 7,  roles: ['pre_sales'] },
  2:  { name: 'Presentar Credenciales',     maxDays: 10, roles: ['pre_sales'] },
  3:  { name: 'Taller Requerimientos',      maxDays: 10, roles: ['pre_sales', 'bdr'] },
  4:  { name: 'Realizando Propuesta',       maxDays: 7,  roles: ['bdr'] },
  16: { name: 'Propuesta Enviada',          maxDays: 14, roles: ['bdr'] },
  5:  { name: 'Negociaciones',              maxDays: 15, roles: ['bdr'] },
  9:  { name: 'Calientes',                  maxDays: 10, roles: ['bdr'] },
};

const CGO_EMAIL = 'roberto.esparza@bambu-techservices.com';
const CGO_NAME = 'Roberto Esparza';

  const SALES_TEAM = {                                                                                                            
    // Pre Sales (MQL -> Taller)                                                                                                                                             
    24060159: { name: 'Samantha Rivas',        email: 'samantha.rivas@bambu-techservices.com',  role: 'pre_sales' },                                                         
    25431089: { name: 'Vicente Varela',        email: 'vicente.varela@bambu-techservices.com',  role: 'pre_sales' },                                                         
    25752795: { name: 'Emilio Mendoza',        email: 'emilio.mendoza@bambu-techservices.com',  role: 'pre_sales' },                                                         
    11865784: { name: 'Sofia Santiago',        email: 'sofia@bambu-techservices.com',           role: 'pre_sales' },
    26438238: { name: 'Harold Bautista',       email: 'harold.bautista@bambu-techservices.com', role: 'pre_sales' },

    // BDRs (Taller -> Calientes)
    16167654: { name: 'Cecia Lozano',          email: 'cecia.lozano@bambu-techservices.com',     role: 'bdr' },
    23975173: { name: 'Itzel Arias',           email: 'itzel.arias@bambu-techservices.com',      role: 'bdr' },
    25224993: { name: 'Luis Fernando Castro',  email: 'luis.castro@bambu-techservices.com',      role: 'bdr' },
    26082729: { name: 'Victor Villafane',      email: 'victor.villafane@bambu-techservices.com', role: 'bdr' },
    26148685: { name: 'Gabriela Rivero',       email: 'gabriela.rivero@bambu-techservices.com',  role: 'bdr' },
    25898347: { name: 'Nayeli Gomez',          email: 'nayeli.gomez@bambu-techservices.com',     role: 'bdr' },

    // CGO
    14406657: { name: 'Roberto Esparza',       email: 'roberto.esparza@bambu-techservices.com',  role: 'cgo' },

    // Sin rol formal - alertas se envian solo al CGO como fallback
    1819933:  { name: 'Alonso Santiago',       email: 'alonso@bambu-techservices.com',           role: 'unassigned' },
    24992387: { name: 'Daniel Sanchez',        email: 'daniel.sanchez@bambu-techservices.com',   role: 'unassigned' },
    23841490: { name: 'Jose Mendez',           email: 'jose.mendez@bambu-techservices.com',      role: 'unassigned' },
    23269567: { name: 'Omar',                  email: 'omar@bambu-techservices.com',             role: 'unassigned' },
  };

const PIPEDRIVE_DOMAIN = 'bambumobile';

// Limite de reps a procesar (0 = sin limite). Para testing inicial.
// Rollout: 1 (prueba 1 rep) -> 4 (solo pre_sales) -> 8 (todos) -> 0 (full)
const MAX_REPS_PER_RUN = 0;

// Incluir el resumen ejecutivo para CGO?
const INCLUDE_EXEC_SUMMARY = true;

// Enviar copia CC al CGO de cada coaching card individual?
const CC_CGO_ON_INDIVIDUAL = true;

// ============================
// TEST MODE - Fase A
// true  = TODOS los emails (individuales + exec) van a TEST_EMAIL y llevan [TEST] en subject
// false = modo produccion normal
// ============================
const TEST_MODE = false;
const TEST_EMAIL = 'roberto.esparza@bambu-techservices.com';


// ============================================
// SECCION 2: HELPERS
// ============================================

function extractId(value) {
  if (value === null || value === undefined) return null;
  if (typeof value === 'object') return value.id;
  return value;
}

function mondayOfCurrentWeek(ref) {
  const d = new Date(ref);
  d.setHours(0, 0, 0, 0);
  const day = d.getDay(); // 0=Dom, 1=Lun, ..., 6=Sab
  const diff = day === 0 ? -6 : 1 - day; // si es domingo, retrocede 6; sino, retrocede a lunes
  d.setDate(d.getDate() + diff);
  return d;
}

function formatMoneyMXN(value) {
  const n = Number(value || 0);
  if (!n) return '$0 MXN';
  return '$' + n.toLocaleString('es-MX', { maximumFractionDigits: 0 }) + ' MXN';
}

function formatDateShort(d) {
  return new Date(d).toLocaleDateString('es-MX', { day: 'numeric', month: 'short' });
}

function truncate(s, n) {
  const str = String(s || '');
  return str.length > n ? str.slice(0, n - 1) + '…' : str;
}

function parseBool(v) {
  if (v === true || v === false) return v;
  if (typeof v === 'string') return v.toLowerCase() === 'true';
  return Boolean(v);
}


// ============================================
// SECCION 3: LECTURA DE DATOS
// ============================================

const now = new Date();
const weekStart = mondayOfCurrentWeek(now);
const weekStartISO = weekStart.toISOString();

const weekRangeLabel = `${formatDateShort(weekStart)} - ${formatDateShort(now)}`;

// Deals consolidados del nodo "Consolidate Deals"
// Ese nodo previo devuelve 1 item con { deals: [...], count: N }
let allDeals = [];
try {
  const consolidated = $('Consolidate Deals').first().json;
  allDeals = Array.isArray(consolidated.deals) ? consolidated.deals : [];
} catch (e) {
  // Fallback: si no existe el nodo, intentamos leer de $input del nodo previo
  // buscando .json.data (formato raw del HTTP Pipedrive)
  for (const item of $input.all()) {
    if (item.json && Array.isArray(item.json.data)) {
      allDeals = allDeals.concat(item.json.data);
    }
  }
}

// Sheet rows del nodo inmediato anterior (Google Sheets "Read WF-03 Alerts")
// Cada item es una fila del sheet. Filtramos por timestamp >= lunes de esta semana.
const sheetRows = $input.all().map(i => i.json).filter(r => {
  if (!r || !r.timestamp) return false;
  try {
    return new Date(r.timestamp) >= weekStart;
  } catch (e) {
    return false;
  }
});


// ============================================
// SECCION 4: AGREGACION POR REP
// ============================================

// Inicializar stats solo para pre_sales y bdr (el CGO tiene su propio resumen)
const repStats = {};
for (const [userId, info] of Object.entries(SALES_TEAM)) {
  if (info.role !== 'pre_sales' && info.role !== 'bdr') continue;
  repStats[userId] = {
    user_id: Number(userId),
    name: info.name,
    email: info.email,
    role: info.role,
    role_label: info.role === 'pre_sales' ? 'Pre Sales' : 'BDR',
    deals_owned: 0,
    deals_open: 0,
    deals_won_week: 0,
    deals_lost_week: 0,
    deals_moved_week: 0,
    deals_no_activity_week: 0,
    alerts_week: 0,
    escalaciones: 0,
    urgentes: 0,
    suaves: 0,
    inactividad: 0,
    mismatches: 0,
    top_risk_deals: [],
    total_value_open: 0,
  };
}

// Loop deals de Pipedrive
for (const deal of allDeals) {
  const userId = String(extractId(deal.user_id));
  const stats = repStats[userId];
  if (!stats) continue; // no es pre_sales ni bdr

  stats.deals_owned++;

  const status = (deal.status || 'open').toLowerCase();
  if (status === 'open') {
    stats.deals_open++;
    stats.total_value_open += Number(deal.value || 0);
  } else if (status === 'won') {
    if (deal.won_time && new Date(deal.won_time) >= weekStart) {
      stats.deals_won_week++;
    }
  } else if (status === 'lost') {
    if (deal.lost_time && new Date(deal.lost_time) >= weekStart) {
      stats.deals_lost_week++;
    }
  }

  // Solo contamos movimiento y actividad en deals abiertos
  if (status !== 'open') continue;

  // Deal cambio de etapa esta semana?
  if (deal.stage_change_time) {
    const sct = new Date(deal.stage_change_time);
    if (sct >= weekStart) stats.deals_moved_week++;
  }

  // Sin actividad esta semana?
  const lastAct = deal.last_activity_date ? new Date(deal.last_activity_date) : null;
  if (!lastAct || lastAct < weekStart) {
    stats.deals_no_activity_week++;
  }
}

// Loop alertas del Sheet (match por owner_name)
const repsByName = {};
for (const stats of Object.values(repStats)) {
  repsByName[stats.name] = stats;
}

for (const row of sheetRows) {
  const rep = repsByName[row.owner_name];
  if (!rep) continue; // alerta de CGO, unassigned u otro

  rep.alerts_week++;

  const type = String(row.alert_type || '').toLowerCase();
  if (type === 'escalacion') rep.escalaciones++;
  else if (type === 'urgente') rep.urgentes++;
  else if (type === 'suave') rep.suaves++;
  else if (type === 'inactividad') rep.inactividad++;

  if (parseBool(row.mismatch_flag)) rep.mismatches++;

  const days = Number(row.days_in_stage || 0);
  const value = Number(row.value || 0);
  const risk = days * (value || 1); // si no hay valor, al menos ordena por dias

  rep.top_risk_deals.push({
    title: row.deal_title || 'Sin titulo',
    org: row.org_name || 'Sin organizacion',
    value,
    days,
    stage: row.stage_name || '',
    type,
    url: row.deal_url || '',
    risk,
  });
}

// Dedupe top_risk_deals por url (puede haber múltiples alertas del mismo deal en la semana)
// y quedarnos con la de mayor risk
for (const stats of Object.values(repStats)) {
  const bestByUrl = {};
  for (const d of stats.top_risk_deals) {
    const key = d.url || `${d.title}|${d.org}`;
    if (!bestByUrl[key] || d.risk > bestByUrl[key].risk) {
      bestByUrl[key] = d;
    }
  }
  stats.top_risk_deals = Object.values(bestByUrl)
    .sort((a, b) => b.risk - a.risk)
    .slice(0, 3);
}


// ============================================
// SECCION 5: COACHING RULES
// ============================================

function generateCoachingMessage(s) {
  // Orden de prioridad: más critico primero

  if (s.deals_open === 0 && s.deals_owned === 0) {
    return {
      flag: '🔴',
      headline: 'Sin pipeline asignado',
      action: 'Agenda 1:1 con CGO esta semana para revisar asignacion de cuentas o empezar prospeccion activa.',
    };
  }

  if (s.deals_open === 0) {
    return {
      flag: '🟡',
      headline: 'Sin deals abiertos',
      action: 'Todos tus deals estan cerrados. Enfoca el lunes en prospeccion outbound y llenar el pipeline.',
    };
  }

  if (s.escalaciones >= 3) {
    return {
      flag: '🔴',
      headline: `${s.escalaciones} deals escalados`,
      action: 'Agenda 1:1 con CGO el lunes para revisar reasignaciones o cierres por perdida. No acumules mas escalaciones.',
    };
  }

  if (s.deals_moved_week === 0 && s.deals_open >= 3) {
    return {
      flag: '🔴',
      headline: '0 deals avanzados esta semana',
      action: 'Bloquea 2 horas el lunes a primera hora para revisar y mover al menos 2 deals de etapa. Sin movimiento no hay pipeline.',
    };
  }

  if (s.urgentes >= 5) {
    return {
      flag: '🟠',
      headline: `${s.urgentes} deals urgentes acumulados`,
      action: 'Dedica la manana del lunes a contactar cada deal urgente HOY. Toma decision: avanzar, reasignar o cerrar.',
    };
  }

  if (s.mismatches >= 2) {
    return {
      flag: '🟠',
      headline: `${s.mismatches} deals fuera de tu rol`,
      action: 'Tienes deals en etapas que no corresponden a tu rol. Coordina con CGO para reasignar o actualizar el owner en Pipedrive.',
    };
  }

  const noActivityRatio = s.deals_open > 0 ? s.deals_no_activity_week / s.deals_open : 0;
  if (noActivityRatio > 0.5 && s.deals_open >= 4) {
    return {
      flag: '🟡',
      headline: `${s.deals_no_activity_week} deals sin actividad semanal`,
      action: 'Mas del 50% de tus deals abiertos no tienen actividad esta semana. Registra llamadas, emails o tareas en Pipedrive para mantener el pulso.',
    };
  }

  if (s.deals_moved_week >= 3 && s.escalaciones === 0 && s.urgentes <= 2) {
    return {
      flag: '🟢',
      headline: 'Semana limpia y con movimiento',
      action: `Excelente ritmo: ${s.deals_moved_week} deals avanzados y pipeline sano. Enfocate en cerrar los de etapa Negociaciones/Calientes.`,
    };
  }

  if (s.deals_won_week >= 1) {
    return {
      flag: '🟢',
      headline: `${s.deals_won_week} deal(s) ganado(s) esta semana`,
      action: 'Felicidades. Pide referidos a ese cliente antes de 7 dias y mantén el ritmo en los deals de Negociaciones.',
    };
  }

  return {
    flag: '🟡',
    headline: 'Semana estable',
    action: 'Revisa tus Top 3 deals en riesgo de abajo y prioriza accion concreta para cada uno el lunes.',
  };
}

for (const stats of Object.values(repStats)) {
  stats.coaching = generateCoachingMessage(stats);
}


// ============================================
// SECCION 6: HTML TEMPLATES
// ============================================

function renderRepTopRiskTable(topDeals) {
  if (!topDeals || topDeals.length === 0) {
    return `<tr><td colspan="4" style="padding:12px;text-align:center;color:#999;font-style:italic">Sin deals en riesgo esta semana</td></tr>`;
  }
  return topDeals.map((d, i) => `
    <tr>
      <td style="padding:8px;border-bottom:1px solid #f0f0f0;color:#888;width:24px">${i + 1}</td>
      <td style="padding:8px;border-bottom:1px solid #f0f0f0">
        <a href="${d.url}" style="color:#0073ea;text-decoration:none;font-weight:600">${truncate(d.title, 48)}</a>
        <div style="color:#888;font-size:12px">${truncate(d.org, 48)} · ${d.stage}</div>
      </td>
      <td style="padding:8px;border-bottom:1px solid #f0f0f0;text-align:right;white-space:nowrap">${formatMoneyMXN(d.value)}</td>
      <td style="padding:8px;border-bottom:1px solid #f0f0f0;text-align:right;white-space:nowrap;color:#c0392b;font-weight:600">${d.days}d</td>
    </tr>
  `).join('');
}

function renderCoachingCard(s) {
  const c = s.coaching;
  const colorMap = {
    '🟢': { bg: '#27ae60', light: '#e8f5e9' },
    '🟡': { bg: '#f39c12', light: '#fff8e1' },
    '🟠': { bg: '#e67e22', light: '#ffebd4' },
    '🔴': { bg: '#c0392b', light: '#ffe8e8' },
  };
  const colors = colorMap[c.flag] || colorMap['🟡'];

  return `
<div style="font-family:Arial,Helvetica,sans-serif;max-width:680px;margin:0 auto;background:#ffffff">

  <div style="background:${colors.bg};padding:20px 24px;border-radius:8px 8px 0 0">
    <div style="color:#ffffff;font-size:12px;text-transform:uppercase;letter-spacing:1px;opacity:0.85">Pipeline Pulse Semanal</div>
    <h2 style="color:#ffffff;margin:4px 0 0;font-size:20px;font-weight:700">${s.name}</h2>
    <div style="color:#ffffff;font-size:13px;margin-top:4px;opacity:0.9">${s.role_label} · Semana ${weekRangeLabel}</div>
  </div>

  <div style="border:1px solid #e0e0e0;border-top:none;padding:24px;border-radius:0 0 8px 8px">

    <div style="margin-bottom:24px;padding:18px;background:${colors.light};border-left:4px solid ${colors.bg};border-radius:0 6px 6px 0">
      <div style="font-size:24px;line-height:1">${c.flag}</div>
      <div style="font-weight:700;font-size:16px;color:#333;margin-top:6px">${c.headline}</div>
      <div style="color:#555;font-size:14px;margin-top:8px;line-height:1.5">${c.action}</div>
    </div>

    <h3 style="color:#333;font-size:14px;text-transform:uppercase;letter-spacing:0.5px;margin:0 0 12px;border-bottom:2px solid #f0f0f0;padding-bottom:8px">Tu semana en numeros</h3>
    <table style="width:100%;border-collapse:collapse;font-size:14px;margin-bottom:24px">
      <tr>
        <td style="padding:10px 8px;background:#f8f9fa;border-radius:4px 0 0 4px;width:50%">
          <div style="color:#888;font-size:11px;text-transform:uppercase">Deals abiertos</div>
          <div style="font-size:24px;font-weight:700;color:#333">${s.deals_open}</div>
          <div style="color:#888;font-size:12px;margin-top:2px">${formatMoneyMXN(s.total_value_open)} en pipeline</div>
        </td>
        <td style="padding:10px 8px;background:#f8f9fa;border-radius:0 4px 4px 0;width:50%">
          <div style="color:#888;font-size:11px;text-transform:uppercase">Avanzados esta semana</div>
          <div style="font-size:24px;font-weight:700;color:${s.deals_moved_week > 0 ? '#27ae60' : '#c0392b'}">${s.deals_moved_week}</div>
          <div style="color:#888;font-size:12px;margin-top:2px">${s.deals_no_activity_week} sin actividad</div>
        </td>
      </tr>
    </table>

    <table style="width:100%;border-collapse:collapse;font-size:13px;margin-bottom:24px">
      <tr style="background:#f8f9fa">
        <td style="padding:10px 8px;text-align:center;border-radius:4px 0 0 4px">
          <div style="color:#888;font-size:11px;text-transform:uppercase">Alertas</div>
          <div style="font-size:18px;font-weight:700;color:#333">${s.alerts_week}</div>
        </td>
        <td style="padding:10px 8px;text-align:center">
          <div style="color:#888;font-size:11px;text-transform:uppercase">🚨 Escalacion</div>
          <div style="font-size:18px;font-weight:700;color:${s.escalaciones > 0 ? '#8e1600' : '#333'}">${s.escalaciones}</div>
        </td>
        <td style="padding:10px 8px;text-align:center">
          <div style="color:#888;font-size:11px;text-transform:uppercase">🔴 Urgente</div>
          <div style="font-size:18px;font-weight:700;color:${s.urgentes > 0 ? '#c0392b' : '#333'}">${s.urgentes}</div>
        </td>
        <td style="padding:10px 8px;text-align:center">
          <div style="color:#888;font-size:11px;text-transform:uppercase">⚠️ Suave</div>
          <div style="font-size:18px;font-weight:700;color:#333">${s.suaves}</div>
        </td>
        <td style="padding:10px 8px;text-align:center;border-radius:0 4px 4px 0">
          <div style="color:#888;font-size:11px;text-transform:uppercase">💤 Inactividad</div>
          <div style="font-size:18px;font-weight:700;color:#333">${s.inactividad}</div>
        </td>
      </tr>
    </table>

    ${s.mismatches > 0 ? `
    <div style="margin-bottom:24px;padding:12px 16px;background:#ffe8e8;border-left:4px solid #c0392b;border-radius:0 4px 4px 0;font-size:13px;color:#555">
      <strong style="color:#c0392b">⚠️ ${s.mismatches} mismatch(es) detectados:</strong> tienes deals en etapas fuera de tu rol (${s.role_label}). Coordina con CGO para reasignar.
    </div>` : ''}

    <h3 style="color:#333;font-size:14px;text-transform:uppercase;letter-spacing:0.5px;margin:0 0 12px;border-bottom:2px solid #f0f0f0;padding-bottom:8px">Tus Top 3 deals en riesgo</h3>
    <table style="width:100%;border-collapse:collapse;font-size:13px;margin-bottom:20px">
      ${renderRepTopRiskTable(s.top_risk_deals)}
    </table>

    <div style="text-align:center;margin:24px 0 8px">
      <a href="https://${PIPEDRIVE_DOMAIN}.pipedrive.com/pipeline/1/user/${s.user_id}" style="background:#0073ea;color:#ffffff;padding:12px 32px;text-decoration:none;border-radius:6px;font-weight:600;font-size:14px;display:inline-block">
        Ver tu pipeline en Pipedrive
      </a>
    </div>
  </div>

  <div style="padding:14px;text-align:center;color:#bbb;font-size:11px">
    WF-08 Pipeline Pulse Semanal · Bambu Tech Services · ${now.toLocaleDateString('es-MX', { weekday: 'long', day: 'numeric', month: 'long', year: 'numeric' })}
  </div>
</div>`;
}


function renderExecSummary(reps, totals, topRiskGlobal) {
  const sortedReps = reps.slice().sort((a, b) => {
    // Orden: 1) mas escalaciones, 2) mas urgentes, 3) menos deals avanzados
    if (b.escalaciones !== a.escalaciones) return b.escalaciones - a.escalaciones;
    if (b.urgentes !== a.urgentes) return b.urgentes - a.urgentes;
    return a.deals_moved_week - b.deals_moved_week;
  });

  const repRows = sortedReps.map(r => {
    const c = r.coaching;
    const rowColor = c.flag === '🔴' ? '#ffe8e8' : c.flag === '🟠' ? '#fff3e0' : c.flag === '🟡' ? '#fffde7' : '#e8f5e9';
    return `
      <tr style="background:${rowColor}">
        <td style="padding:10px 8px;font-weight:600">${c.flag} ${r.name}</td>
        <td style="padding:10px 8px;color:#666;font-size:12px">${r.role_label}</td>
        <td style="padding:10px 8px;text-align:center">${r.deals_open}</td>
