for (const deal of openDeals) {
  const val = deal.value || 0;
  const sid = deal.stage_id;
  const cfg = STAGE_CONFIG[sid] || {name:`Stage ${sid}`, emoji:'', weight:0.1};
  bruto    += val;
  ponderado += val * cfg.weight;
  if (!byStage[sid]) byStage[sid] = {name:cfg.name, emoji:cfg.emoji, count:0, bruto:0};
  byStage[sid].count++;
  byStage[sid].bruto += val;
