function extractId(value) {
  if (value === null || value === undefined) return null;
  if (typeof value === 'object') return value.id;
  return value;
}

function mondayOfCurrentWeek(ref) {
  const d = new Date(ref);
  d.setHours(0, 0, 0, 0);
  const day = d.getDay(); // 0=Dom, 1=Lun, ..., 6=Sab
  const diff = day === 0 ? -6 : 1 - day; // si es domingo, retrocede 6; sino, retrocede a lunes
  d.setDate(d.getDate() + diff);
  return d;
}

function formatMoneyMXN(value) {
  const n = Number(value || 0);
  if (!n) return '$0 MXN';
  return '$' + n.toLocaleString('es-MX', { maximumFractionDigits: 0 }) + ' MXN';
}

function formatDateShort(d) {
  return new Date(d).toLocaleDateString('es-MX', { day: 'numeric', month: 'short' });
}

function truncate(s, n) {
  const str = String(s || '');
  return str.length > n ? str.slice(0, n - 1) + '…' : str;
}

function parseBool(v) {
  if (v === true || v === false) return v;
  if (typeof v === 'string') return v.toLowerCase() === 'true';
  return Boolean(v);
}


// ============================================
// SECCION 3: LECTURA DE DATOS
// ============================================

const now = new Date();
const weekStart = mondayOfCurrentWeek(now);
const weekStartISO = weekStart.toISOString();

const weekRangeLabel = `${formatDateShort(weekStart)} - ${formatDateShort(now)}`;

// Deals consolidados del nodo "Consolidate Deals"
// Ese nodo previo devuelve 1 item con { deals: [...], count: N }
let allDeals = [];
try {
  const consolidated = $('Consolidate Deals').first().json;
  allDeals = Array.isArray(consolidated.deals) ? consolidated.deals : [];
} catch (e) {
  // Fallback: si no existe el nodo, intentamos leer de $input del nodo previo
  // buscando .json.data (formato raw del HTTP Pipedrive)
  for (const item of $input.all()) {
    if (item.json && Array.isArray(item.json.data)) {
      allDeals = allDeals.concat(item.json.data);
    }
  }
}

// Sheet rows del nodo inmediato anterior (Google Sheets "Read WF-03 Alerts")
// Cada item es una fila del sheet. Filtramos por timestamp >= lunes de esta semana.
const sheetRows = $input.all().map(i => i.json).filter(r => {
  if (!r || !r.timestamp) return false;
  try {
    return new Date(r.timestamp) >= weekStart;
  } catch (e) {
    return false;
  }
});


// ============================================
// SECCION 4: AGREGACION POR REP
// ============================================

// Inicializar stats solo para pre_sales y bdr (el CGO tiene su propio resumen)
const repStats = {};
for (const [userId, info] of Object.entries(SALES_TEAM)) {
  if (info.role !== 'pre_sales' && info.role !== 'bdr') continue;
  repStats[userId] = {
    user_id: Number(userId),
    name: info.name,
    email: info.email,
    role: info.role,
    role_label: info.role === 'pre_sales' ? 'Pre Sales' : 'BDR',
    deals_owned: 0,
    deals_open: 0,
    deals_won_week: 0,
    deals_lost_week: 0,
    deals_moved_week: 0,
    deals_no_activity_week: 0,
    alerts_week: 0,
    escalaciones: 0,
    urgentes: 0,
    suaves: 0,
    inactividad: 0,
    mismatches: 0,
    top_risk_deals: [],
    total_value_open: 0,
  };
}

// Loop deals de Pipedrive
for (const deal of allDeals) {
  const userId = String(extractId(deal.user_id));
  const stats = repStats[userId];
  if (!stats) continue; // no es pre_sales ni bdr

  stats.deals_owned++;

  const status = (deal.status || 'open').toLowerCase();
  if (status === 'open') {
    stats.deals_open++;
    stats.total_value_open += Number(deal.value || 0);
  } else if (status === 'won') {
    if (deal.won_time && new Date(deal.won_time) >= weekStart) {
      stats.deals_won_week++;
    }
  } else if (status === 'lost') {
    if (deal.lost_time && new Date(deal.lost_time) >= weekStart) {
      stats.deals_lost_week++;
    }
  }

  // Solo contamos movimiento y actividad en deals abiertos
  if (status !== 'open') continue;

  // Deal cambio de etapa esta semana?
  if (deal.stage_change_time) {
    const sct = new Date(deal.stage_change_time);
    if (sct >= weekStart) stats.deals_moved_week++;
  }

  // Sin actividad esta semana?
  const lastAct = deal.last_activity_date ? new Date(deal.last_activity_date) : null;
  if (!lastAct || lastAct < weekStart) {
    stats.deals_no_activity_week++;
  }
}

// Loop alertas del Sheet (match por owner_name)
const repsByName = {};
for (const stats of Object.values(repStats)) {
  repsByName[stats.name] = stats;
}

for (const row of sheetRows) {
  const rep = repsByName[row.owner_name];
  if (!rep) continue; // alerta de CGO, unassigned u otro

  rep.alerts_week++;

  const type = String(row.alert_type || '').toLowerCase();
  if (type === 'escalacion') rep.escalaciones++;
  else if (type === 'urgente') rep.urgentes++;
  else if (type === 'suave') rep.suaves++;
  else if (type === 'inactividad') rep.inactividad++;

  if (parseBool(row.mismatch_flag)) rep.mismatches++;

  const days = Number(row.days_in_stage || 0);
  const value = Number(row.value || 0);
  const risk = days * (value || 1); // si no hay valor, al menos ordena por dias

  rep.top_risk_deals.push({
    title: row.deal_title || 'Sin titulo',
    org: row.org_name || 'Sin organizacion',
    value,
    days,
    stage: row.stage_name || '',
    type,
    url: row.deal_url || '',
    risk,
  });
}

// Dedupe top_risk_deals por url (puede haber múltiples alertas del mismo deal en la semana)
// y quedarnos con la de mayor risk
for (const stats of Object.values(repStats)) {
  const bestByUrl = {};
  for (const d of stats.top_risk_deals) {
    const key = d.url || `${d.title}|${d.org}`;
    if (!bestByUrl[key] || d.risk > bestByUrl[key].risk) {
      bestByUrl[key] = d;
    }
  }
  stats.top_risk_deals = Object.values(bestByUrl)
    .sort((a, b) => b.risk - a.risk)
    .slice(0, 3);
}


