  if (s.deals_open === 0) {
    return {
      flag: '🟡',
      headline: 'Sin deals abiertos',
      action: 'Todos tus deals estan cerrados. Enfoca el lunes en prospeccion outbound y llenar el pipeline.',
    };
  }

  if (s.escalaciones >= 3) {
    return {
      flag: '🔴',
      headline: `${s.escalaciones} deals escalados`,
      action: 'Agenda 1:1 con CGO el lunes para revisar reasignaciones o cierres por perdida. No acumules mas escalaciones.',
    };
  }

  if (s.deals_moved_week === 0 && s.deals_open >= 3) {
    return {
      flag: '🔴',
      headline: '0 deals avanzados esta semana',
      action: 'Bloquea 2 horas el lunes a primera hora para revisar y mover al menos 2 deals de etapa. Sin movimiento no hay pipeline.',
    };
  }

  if (s.urgentes >= 5) {
    return {
      flag: '🟠',
      headline: `${s.urgentes} deals urgentes acumulados`,
      action: 'Dedica la manana del lunes a contactar cada deal urgente HOY. Toma decision: avanzar, reasignar o cerrar.',
    };
  }

  if (s.mismatches >= 2) {
    return {
      flag: '🟠',
      headline: `${s.mismatches} deals fuera de tu rol`,
      action: 'Tienes deals en etapas que no corresponden a tu rol. Coordina con CGO para reasignar o actualizar el owner en Pipedrive.',
    };
  }

  const noActivityRatio = s.deals_open > 0 ? s.deals_no_activity_week / s.deals_open : 0;
  if (noActivityRatio > 0.5 && s.deals_open >= 4) {
    return {
      flag: '🟡',
      headline: `${s.deals_no_activity_week} deals sin actividad semanal`,
      action: 'Mas del 50% de tus deals abiertos no tienen actividad esta semana. Registra llamadas, emails o tareas en Pipedrive para mantener el pulso.',
    };
  }

  if (s.deals_moved_week >= 3 && s.escalaciones === 0 && s.urgentes <= 2) {
    return {
      flag: '🟢',
      headline: 'Semana limpia y con movimiento',
      action: `Excelente ritmo: ${s.deals_moved_week} deals avanzados y pipeline sano. Enfocate en cerrar los de etapa Negociaciones/Calientes.`,
    };
  }

  if (s.deals_won_week >= 1) {
    return {
      flag: '🟢',
      headline: `${s.deals_won_week} deal(s) ganado(s) esta semana`,
      action: 'Felicidades. Pide referidos a ese cliente antes de 7 dias y mantén el ritmo en los deals de Negociaciones.',
    };
  }

  return {
    flag: '🟡',
    headline: 'Semana estable',
    action: 'Revisa tus Top 3 deals en riesgo de abajo y prioriza accion concreta para cada uno el lunes.',
  };
}

for (const stats of Object.values(repStats)) {
